// Datamoshing HLSL Shader
float4 main(PS_INPUT input) : SV_Target
{
    // Fetch the original pixel color
    float4 originalColor = tex2D(sampler, input.texCoord);

    // Create a random offset for datamoshing
    float2 offset = frac(sin(float2(dot(input.texCoord.xy, float2(12.9898, 78.233))) * 43758.5453));

