#include <stdio.h>

int main() {
    int n; // Number of elements in the table
    int i;
    int data[100]; // Array to hold the user's data

    printf("Enter the number of elements you want in your table (up to 100): ");
    scanf("%d", &n);

    // Input validation
    if (n > 100) {
        printf("Number too large! Please enter a number up to 100.\n");
        return 1;
    }

    printf("Enter %d integers:\n", n);
    for (i = 0; i < n; i++) {
        printf("Element %d: ", i + 1);
        scanf("%d", &data[i]);
    }

    printf("\nYour Sequential Table:\n");
    for (i = 0; i < n; i++) {
        printf("%d ", data[i]);
    }
    printf("\n");

    return 0;
}
```

This code does the following:
1. Prompts the user to enter the number of elements they want in their table.
2. Validates the input to ensure it doesn't exceed 100.
3. Asks the user to input each integer one by one.
4. Displays the entered numbers as a sequential table.

